@app.function()
@modal.asgi_app()
def fastapi_app():
    from fastapi import FastAPI
    from pydantic import BaseModel
    from typing import List, Any

    web_app = FastAPI()

    class TransformRequest(BaseModel):
        data: List[Any]
        operation: str

    @web_app.get("/ping")
    async def ping():
        return {"pong": True}

    @web_app.post("/transform")
    async def transform(req: TransformRequest):
        data = req.data
        operation = req.operation

        if operation == "sum":
            result = sum(data)
        elif operation == "max":
            result = max(data)
        elif operation == "min":
            result = min(data)
        elif operation == "sort":
            result = sorted(data)
        else:
            return {"error": "Invalid operation", "operation": operation}

        return {"result": result, "operation": operation}

    return web_app

# Separate @app.function() named validate_input
@app.function()
def validate_input(data, operation):
    valid_ops = ["sum", "max", "min", "sort"]
    return operation in valid_ops and isinstance(data, list) and len(data) > 0

