@app.local_entrypoint()
def main():
    # Call validate_input.remote([1,2,3], 'sum')
    result = validate_input.remote([1, 2, 3], 'sum')

    # Write result to /home/user/modal_project/validation_result.txt
    import os
    os.makedirs("/home/user/modal_project", exist_ok=True)
